arguments.argument:
if global.gamePaused=false
{
  if explodeProg=0
  {
    circleWarnRad-=0.33
    if circleWarnRad<=0
    {
      bCanDealDamage=1
      explodeProg=1
    }
  }
  else if explodeProg=1
  {
    image_index+=0.5
    if image_index>=image_number-0.5 {instance_destroy()}
  }
}
